export default ".snipalt-toast {\r\n  position: fixed;\r\n  top: 20px;\r\n  right: 20px;\r\n  z-index: 2147483647;\r\n  font-family: -apple-system, BlinkMacSystemFont, \"Segoe UI\", Roboto, Helvetica, Arial, sans-serif;\r\n  animation: snipalt-slide-in 0.3s ease-out;\r\n}\r\n\r\n.snipalt-toast-content {\r\n  background: white;\r\n  border-radius: 12px;\r\n  padding: 12px 16px;\r\n  box-shadow: 0 10px 25px -5px rgba(0, 0, 0, 0.1), 0 8px 10px -6px rgba(0, 0, 0, 0.1);\r\n  display: flex;\r\n  align-items: center;\r\n  gap: 12px;\r\n  border: 1px solid #e2e8f0;\r\n  min-width: 250px;\r\n  max-width: 350px;\r\n}\r\n\r\n.snipalt-toast-icon {\r\n  font-size: 20px;\r\n}\r\n\r\n.snipalt-toast-text {\r\n  display: flex;\r\n  flex-direction: column;\r\n}\r\n\r\n.snipalt-toast-text strong {\r\n  font-size: 14px;\r\n  color: #1e293b;\r\n  margin: 0;\r\n}\r\n\r\n.snipalt-toast-text p {\r\n  font-size: 12px;\r\n  color: #64748b;\r\n  margin: 2px 0 0 0;\r\n  white-space: nowrap;\r\n  overflow: hidden;\r\n  text-overflow: ellipsis;\r\n}\r\n\r\n@keyframes snipalt-slide-in {\r\n  from {\r\n    transform: translateX(100%);\r\n    opacity: 0;\r\n  }\r\n  to {\r\n    transform: translateX(0);\r\n    opacity: 1;\r\n  }\r\n}\r\n"